/**
 * Image Gallery feature — view, select, and bulk-download images
 * generated by DALL-E, code interpreter charts, and uploads.
 *
 * Includes:
 *   - Gallery grid overlay with tabs (Images / Charts / Uploads / Public)
 *   - Image card selection with shift-click range select
 *   - Sidebar detail panel (prompt, gen-id, preview conversation)
 *   - Bulk download as ZIP archive (JSZip + FileSaver)
 *   - Image picker dialog for attaching gallery images to prompts
 *   - Share image modal (copy link, X, LinkedIn, Reddit)
 *   - Date-range download, make public, delete operations
 *
 * Original source: content.isolated.end.js lines 9097-9975
 */

import { cachedSettings } from '../isolated-world/settings';
import { closeMenus, downloadFileFromUrl, openUpgradeModal } from '../../utils/shared';
import { isDescendant, addTooltip, toast, showConfirmDialog } from '../isolated-world/ui/primitives';
import { sharePost } from '../isolated-world/api';
import { translate } from './i18n';
import { showDateSelectorDialog } from './export';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Category tabs available in the gallery. */
export type GalleryCategory = 'dalle' | 'chart' | 'upload' | 'public';

/** A gallery image node from the Council API. */
export interface GalleryImageNode {
  image_id: string;
  image?: string;
  download_url?: string;
  prompt?: string;
  title?: string;
  gen_id?: string;
  seed?: string;
  width?: number;
  height?: number;
  category?: string;
  conversation_id?: string;
  created_at?: string | number;
  is_public?: boolean;
  created_by?: { id: string; name?: string };
}

// ---------------------------------------------------------------------------
// Module state
// ---------------------------------------------------------------------------

export let selectedGalleryImage: GalleryImageNode | null = null;
export let allImageNodes: GalleryImageNode[] = [];
let selectedImageGalleryImageIds: string[] = [];
let selectedImagePickerImageIds: string[] = [];
let imageGalleryCurrentTab: GalleryCategory = 'dalle';
let showAll = false;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Format a timestamp into a locale-friendly date string. */
function formatTime(time: unknown): number {
  if (!time) return 0;
  const s = String(time);
  if (s.indexOf('T') !== -1) return new Date(s).getTime();
  if (s.indexOf('.') !== -1 && s.split('.')[0]!.length === 10) return new Date(Number(time) * 1000).getTime();
  if (s.indexOf('.') !== -1 && s.split('.')[0]!.length === 13) return new Date(Number(time)).getTime();
  if (s.length === 13) return new Date(Number(time)).getTime();
  if (s.length === 10) return new Date(Number(time) * 1000).getTime();
  return Number(time);
}

function formatDate(date: Date, showTime = true, longFormat = false): string {
  if (!date) return '';
  const now = new Date();
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);

  const isToday = now.toDateString() === date.toDateString();
  const isYesterday = yesterday.toDateString() === date.toDateString();
  const timeStr = showTime ? ` ${date.toLocaleTimeString('en-US', { hour: 'numeric', minute: 'numeric' })}` : '';

  if (isToday) return `Today${timeStr}`;
  if (isYesterday) return `Yesterday${timeStr}`;
  return `${date.toLocaleDateString('en-US', {
    year: longFormat ? 'numeric' : '2-digit',
    month: longFormat ? 'long' : '2-digit',
    day: '2-digit',
  })}${timeStr}`;
}

function formatDateDalle(): string {
  const d = new Date();
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}.${pad(d.getMinutes())}.${pad(d.getSeconds())}`;
}

function isWindows(): boolean {
  return navigator.platform?.toLowerCase().includes('win') ?? false;
}

function dataURItoBlob(dataURI: string): Blob {
  const [header, data] = dataURI.split(',');
  const byteString = atob(data!);
  const buffer = new ArrayBuffer(byteString.length);
  const view = new Uint8Array(buffer);
  for (let i = 0; i < byteString.length; i++) {
    view[i] = byteString.charCodeAt(i);
  }
  return new Blob([buffer], { type: header!.split(':')[1]!.split(';')[0]! });
}

function sanitizeFileName(name: string): string {
  return (name ?? '').replaceAll(' ', '_').replaceAll('/', '-').replaceAll('\\', '-').replaceAll('.', '_');
}

// ---------------------------------------------------------------------------
// ZIP download
// ---------------------------------------------------------------------------

/**
 * Download gallery images as a ZIP file using JSZip.
 *
 * Original: content.isolated.end.js lines 9233-9279
 */
export async function zipImages(
  images: GalleryImageNode[],
  menuButton: HTMLElement | null = null,
  originalButton: HTMLElement | null = null,
  useWebp = true,
): Promise<void> {
  if (images.length === 0) {
    toast('No images to download');
    resetMenuButton(menuButton, originalButton);
    return;
  }

  // Dynamic import to avoid bundling JSZip when not used
  const [{ default: JSZip }, { saveAs }] = await Promise.all([import('jszip'), import('file-saver')]);

  if (menuButton) menuButton.style.width = '100px';

  const zip = new JSZip();
  const folder = zip.folder('Council-Gallery')!;

  for (let i = 0; i < images.length; i++) {
    if (menuButton) menuButton.innerHTML = `${i + 1}/${images.length}`;

    const img = images[i]!;
    const created = new Date(formatTime(img.created_at));
    const dateStr = `${created.getFullYear()}-${created.getMonth() + 1}-${created.getDate()}__${created.getHours()}-${created.getMinutes()}-${created.getSeconds()}`;
    const titleSlug = sanitizeFileName(img.title ?? '');
    const imageUrl = decodeURIComponent(img.image ?? img.download_url ?? '');
    const ext = useWebp ? 'webp' : isWindows() ? 'jpg' : 'png';
    const filename = `${img.conversation_id}/${dateStr}__${img.image_id}${titleSlug ? `__${titleSlug}` : ''}.${ext}`;

    const dataURI: string = await chrome.runtime.sendMessage({
      type: 'downloadImage',
      detail: { url: imageUrl },
    });
    const blob = dataURItoBlob(dataURI);
    folder.file(filename, blob, { binary: true });

    // Also save prompt metadata as .txt
    const txtFilename = `${img.conversation_id}/${dateStr}__${img.image_id}${titleSlug ? `__${titleSlug}` : ''}.txt`;
    const txtContent = `Conversation URL:\nhttps://chatgpt.com/c/${img.conversation_id ?? ''}\n\nTitle:\n${titleSlug}\n\nPrompt:\n${img.prompt ?? ''}`;
    folder.file(txtFilename, txtContent, { binary: false });
  }

  if (menuButton) menuButton.innerHTML = 'Zipping...';

  const blob = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE' });
  saveAs(blob, `${new Date().toISOString().slice(0, 10)}-council-gallery.zip`);
  resetMenuButton(menuButton, originalButton);
}

function resetMenuButton(el: HTMLElement | null, original: HTMLElement | null): void {
  if (el && original) {
    (el as HTMLButtonElement).disabled = false;
    el.style.width = original.style.width;
    el.innerHTML = original.innerHTML;
  }
}

