/**
 * Download selected (or all) gallery images via the background worker.
 *
 * Original: content.isolated.end.js lines 9220-9232
 */
export async function downloadSelectedImages(
  menuButton: HTMLElement | null = null,
  imageIds: string[] = [],
  conversationId: string | null = null,
  useWebp = true,
): Promise<void> {
  let originalButton: HTMLElement | null = null;
  if (menuButton) {
    originalButton = menuButton.cloneNode(true) as HTMLElement;
    (menuButton as HTMLButtonElement).disabled = true;
    menuButton.innerHTML =
      '<svg x="0" y="0" viewbox="0 0 40 40" class="spinner icon icon-xl" style="height:24px;"><circle fill="transparent" stroke="#ffffff50" stroke-width="2" stroke-linecap="round" stroke-dasharray="125.6" cx="20" cy="20" r="18"></circle></svg>';
  }

  const images: GalleryImageNode[] = await chrome.runtime.sendMessage({
    type: 'getSelectedGalleryImages',
    detail: {
      category: imageGalleryCurrentTab,
      imageIds,
      conversationId,
    },
  });

  await zipImages(images, menuButton, originalButton, useWebp);
}

// ---------------------------------------------------------------------------
// Make public / delete
// ---------------------------------------------------------------------------

export function makeGalleryImagesPublic(): void {
  const target = selectedImageGalleryImageIds.length === 0 ? 'all' : 'selected';
  showConfirmDialog(
    'Make images public',
    `Are you sure you want to make ${target} images public?`,
    'Cancel',
    'Make public',
    null,
    () => {
      chrome.runtime.sendMessage(
        {
          type: 'shareGalleryImages',
          detail: {
            imageIds: selectedImageGalleryImageIds,
            category: imageGalleryCurrentTab,
          },
        },
        (response) => {
          if (response?.success) {
            toast(
              selectedImageGalleryImageIds.length === 0
                ? 'All images are now public'
                : 'Selected images are now public',
            );
          }
        },
      );
    },
    'green',
  );
}

export function deleteGalleryImages(): void {
  const count = selectedImageGalleryImageIds.length;
  const target = count === 0 ? 'all' : `${count} selected`;
  showConfirmDialog(
    'Delete images',
    `Are you sure you want to delete ${target} images? This cannot be undone.`,
    'Cancel',
    'Delete',
    null,
    () => {
      chrome.runtime.sendMessage(
        {
          type: 'deleteGalleryImages',
          detail: {
            imageIds: selectedImageGalleryImageIds,
            category: imageGalleryCurrentTab,
          },
        },
        (response) => {
          if (response?.success) {
            if (selectedImageGalleryImageIds.length === 0) {
              const list = document.querySelector('#gallery-image-list');
              if (list) list.innerHTML = '';
              resetSidebar();
              toast('All images are deleted');
              return;
            }
            allImageNodes = allImageNodes.filter((n) => !selectedImageGalleryImageIds.includes(n.image_id));
            selectedImageGalleryImageIds.forEach((id) => {
              document.querySelector(`#gallery-image-card-${id}`)?.parentElement?.remove();
            });
            toast('Selected images are deleted');
            const first = document.querySelector<HTMLElement>('img[id^="gallery-image-card-"]');
            first?.click();
            resetGallerySelection();
          }
        },
      );
    },
    'red',
  );
}

// ---------------------------------------------------------------------------
