/**
 * Clear gallery image selection state.
 *
 * Original: content.isolated.end.js lines 9389-9399
 */
export function resetGallerySelection(): void {
  selectedImageGalleryImageIds = [];
  document.querySelectorAll<HTMLElement>('[id^="gallery-image-card-"]').forEach((el) => {
    el.classList.remove('opacity-50');
  });
  document.querySelectorAll<HTMLInputElement>('[id^="image-gallery-checkbox"]').forEach((el) => {
    el.checked = false;
    el.classList.add('invisible');
  });
  const bar = document.querySelector<HTMLElement>('#gallery-selection-bar');
  bar?.classList.add('hidden');
  const count = document.querySelector<HTMLElement>('#gallery-selection-count');
  if (count) count.innerText = '0 selected';
}

