/**
 * Load a page of images from the backend and render into the gallery grid.
 *
 * Original: content.isolated.end.js lines 9401-9447
 */
export function loadImageList(page = 1, byUserId = ''): void {
  const userId = byUserId || document.querySelector<HTMLElement>('#by-user-id')?.innerText || '';
  const searchInput = document.querySelector<HTMLInputElement>('#gallery-search');
  const searchTerm = searchInput?.value.toLowerCase() ?? '';
  const grid = document.querySelector<HTMLElement>('#gallery-image-list');
  if (!grid) return;

  if (page === 1) {
    grid.innerHTML = `<div class="group relative flex flex-col w-full justify-start items-start gap-2 p-2 cursor-pointer"><div class="relative flex flex-col w-full h-full justify-center items-center gap-2 text-token-text-primary text-2xl font-bold cursor-pointer hover:shadow-xl rounded-xl"><img style="object-fit:none;aspect-ratio:1;background-color: #111;" src="${chrome.runtime.getURL('images/loading.gif')}" class="row-span-4 mx-auto h-full rounded-md object-scale-down"></div></div>`;
  }

  chrome.runtime.sendMessage({ type: 'checkHasSubscription' }, (hasSub) => {
    if (searchTerm && !hasSub) {
      openUpgradeModal();
      return;
    }

    if (page === 1) {
      selectedImageGalleryImageIds = [];
      selectedGalleryImage = null;
    }

    chrome.runtime.sendMessage(
      {
        type: 'getGalleryImages',
        detail: {
          showAll,
          pageNumber: page,
          byUserId: userId,
          category: imageGalleryCurrentTab === 'public' ? 'dalle' : imageGalleryCurrentTab,
          searchTerm,
          isPublic: imageGalleryCurrentTab === 'public',
        },
      },
      (result) => {
        if (!result) return;
        if (page === 1 && result.error) {
          grid.innerHTML = `<div class="flex flex-col w-full justify-start items-start p-2"><div class="relative flex flex-col w-full h-full justify-center items-center gap-2 p-4 text-token-text-primary text-2xl font-bold cursor-pointer bg-token-main-surface-secondary hover:shadow-xl rounded-xl text-center">${result.error}</div></div>`;
          return;
        }

        if (page === 1) allImageNodes.length = 0;
        allImageNodes.push(...(result?.results ?? []));

        if (page === 1 && result?.results?.length > 0) {
          selectedGalleryImage = result.results[0];
        }

        if (allImageNodes.length === 0 && page === 1) {
          grid.innerHTML = `<div class="flex flex-col w-full justify-start items-start p-2"><div class="relative flex flex-col w-full h-full justify-center items-center gap-2 p-4 text-token-text-primary text-2xl font-bold cursor-pointer bg-token-main-surface-secondary hover:shadow-xl rounded-xl text-center">${translate('No images found')}!</div></div>`;
          return;
        }

        // Render image cards
        const cardsHtml = (result?.results ?? [])
          .map(
            (img: GalleryImageNode) =>
              `<div class="group relative flex flex-col w-full justify-start items-start gap-2 p-2 cursor-pointer" style="font-size:12px;" draggable="false">` +
              `<img id="gallery-image-card-${img.image_id}" src="${img.image ?? img.download_url}" alt="${(img.prompt ?? 'Generated by ChatGPT').replace(/[^a-zA-Z0-9 ]/gi, '')}" style="aspect-ratio:1;" class="bg-token-main-surface-tertiary w-full row-span-4 mx-auto h-full rounded-md object-scale-down ${selectedGalleryImage?.image_id === img.image_id ? 'ring-2' : ''} ring-offset-4">` +
              `<div class="invisible absolute start-3 top-3 group-hover:visible"><button id="image-download-button-${img.image_id}" class="flex h-6 w-6 items-center justify-center rounded bg-black/50"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" class="icon icon-sm text-token-text-primary"><path fill-rule="evenodd" clip-rule="evenodd" d="M7.70711 10.2929C7.31658 9.90237 6.68342 9.90237 6.29289 10.2929C5.90237 10.6834 5.90237 11.3166 6.29289 11.7071L11.2929 16.7071C11.6834 17.0976 12.3166 17.0976 12.7071 16.7071L17.7071 11.7071C18.0976 11.3166 18.0976 10.6834 17.7071 10.2929C17.3166 9.90237 16.6834 9.90237 16.2929 10.2929L13 13.5858L13 4C13 3.44771 12.5523 3 12 3C11.4477 3 11 3.44771 11 4L11 13.5858L7.70711 10.2929ZM5 19C4.44772 19 4 19.4477 4 20C4 20.5523 4.44772 21 5 21H19C19.5523 21 20 20.5523 20 20C20 19.4477 19.5523 19 19 19L5 19Z" fill="currentColor"></path></svg></button></div>` +
              `<input type="checkbox" id="image-gallery-checkbox-${img.image_id}" class="${selectedImageGalleryImageIds.length === 0 ? 'invisible' : ''} absolute end-3 top-3 ${imageGalleryCurrentTab !== 'public' ? 'group-hover:visible' : ''}" style="z-index: 11; cursor: pointer; border-radius: 2px;">` +
              `</div>`,
          )
          .join('');

        const loadMoreHtml =
          result?.next && hasSub
            ? '<div class="group relative flex flex-col w-full justify-center items-center gap-2 p-2 cursor-pointer"><div id="load-more-images-button" class="relative flex flex-col w-full h-full justify-center items-center gap-2 text-token-text-primary text-2xl font-bold cursor-pointer bg-token-main-surface-secondary hover:shadow-xl rounded-xl">Load more...</div></div>'
            : '';

        const html = cardsHtml + loadMoreHtml;

        if (page === 1) {
          grid.innerHTML = html;
        } else {
          document.querySelector('#load-more-images-button')?.parentElement?.remove();
          grid.insertAdjacentHTML('beforeend', html);
        }

        addGalleryImageCardEventListeners(result.results);
        addLoadMoreImagesEventListener(page);

        if (page === 1) {
          const firstCard = document.querySelector<HTMLElement>(`#gallery-image-card-${allImageNodes[0]?.image_id}`);
          firstCard?.click();
        }
      },
    );
  });
}

// ---------------------------------------------------------------------------
// Load more (infinite scroll)
// ---------------------------------------------------------------------------

function addLoadMoreImagesEventListener(currentPage: number): void {
  const button = document.querySelector<HTMLElement>('#load-more-images-button');
  button?.addEventListener('click', () => {
    button.innerHTML = `<img style="object-fit:none;aspect-ratio:1;background-color: #111;" src="${chrome.runtime.getURL('images/loading.gif')}" class="row-span-4 mx-auto h-full rounded-md object-scale-down">`;
    loadImageList(currentPage + 1);
  });

  if (button) {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            button.click();
            observer.disconnect();
          }
        });
      },
      { threshold: 0.5 },
    );
    observer.observe(button);
  }
}

