/**
 * Attach click, download, and checkbox handlers to gallery image cards.
 *
 * Original: content.isolated.end.js lines 9570-9664
 */
export function addGalleryImageCardEventListeners(images?: GalleryImageNode[]): void {
  if (!images) return;
  const imageIds = images.map((img) => img.image_id);

  // Download buttons
  const downloadBtns = [...document.querySelectorAll<HTMLElement>('[id^="image-download-button-"]')].slice(-24);
  downloadBtns.forEach((btn) => {
    addTooltip(btn, { value: 'Download', position: 'top' });
    const id = btn.id.split('image-download-button-')[1];
    if (!id || !imageIds.includes(id)) return;
    btn.addEventListener('click', (e) => {
      const imgEl = document.querySelector<HTMLImageElement>(`#gallery-image-card-${id}`);
      const ext = (e as MouseEvent).shiftKey ? (isWindows() ? 'jpg' : 'png') : 'webp';
      if (imgEl?.src) downloadFileFromUrl(imgEl.src, `${id}.${ext}`);
    });
  });

  // Share buttons
  const shareBtns = [...document.querySelectorAll<HTMLElement>('[id^="image-share-button-"]')].slice(-24);
  shareBtns.forEach((btn) => {
    addTooltip(btn, { value: 'Share', position: 'top' });
    const id = btn.id.split('image-share-button-')[1];
    if (!id || !imageIds.includes(id)) return;
    btn.addEventListener('click', () => {
      const img = images.find((i) => i.image_id === id);
      if (img) createShareImageModal(img);
    });
  });

  // Checkbox selection
  document.querySelectorAll<HTMLInputElement>('[id^="image-gallery-checkbox"]').forEach((cb) => {
    cb.addEventListener('click', (e) => {
      const id = cb.id.split('image-gallery-checkbox-')[1];
      if (!id || !imageIds.includes(id)) return;

      if (cb.checked && !selectedImageGalleryImageIds.includes(id)) {
        if (selectedImageGalleryImageIds.length === 0) {
          document
            .querySelectorAll<HTMLInputElement>('[id^="image-gallery-checkbox"]')
            .forEach((c) => c.classList.remove('invisible'));
          document.querySelector('#gallery-selection-bar')?.classList.remove('hidden');
        }

        // Shift-click range select
        if ((e as MouseEvent).shiftKey && selectedImageGalleryImageIds.length > 0) {
          const allCards = document.querySelectorAll<HTMLElement>('[id^="gallery-image-card-"]');
          const lastIdx = allImageNodes.findIndex(
            (n) => n.image_id === selectedImageGalleryImageIds[selectedImageGalleryImageIds.length - 1],
          );
          const curIdx = allImageNodes.findIndex((n) => n.image_id === id);
          const minIdx = Math.min(lastIdx, curIdx);
          const maxIdx = Math.max(lastIdx, curIdx);
          for (let i = minIdx; i <= maxIdx; i++) {
            const card = allCards[i];
            if (!card) continue;
            card.classList.add('opacity-50');
            const cardId = card.id.split('gallery-image-card-')[1];
            if (cardId && !selectedImageGalleryImageIds.includes(cardId)) {
              selectedImageGalleryImageIds.push(cardId);
              const checkbox = document.querySelector<HTMLInputElement>(`#image-gallery-checkbox-${cardId}`);
              if (checkbox) checkbox.checked = true;
            }
          }
        } else {
          const card = document.querySelector<HTMLElement>(`#gallery-image-card-${id}`);
          card?.classList.add('opacity-50');
          selectedImageGalleryImageIds.push(id);
        }

        const countEl = document.querySelector<HTMLElement>('#gallery-selection-count');
        if (countEl) countEl.innerText = `${selectedImageGalleryImageIds.length} selected`;
      } else {
        selectedImageGalleryImageIds = selectedImageGalleryImageIds.filter((x) => x !== id);
        const countEl = document.querySelector<HTMLElement>('#gallery-selection-count');
        if (countEl) countEl.innerText = `${selectedImageGalleryImageIds.length} selected`;
        document.querySelector(`#gallery-image-card-${id}`)?.classList.remove('opacity-50');
        if (selectedImageGalleryImageIds.length === 0) resetGallerySelection();
      }
    });
  });

  // Image card click — update sidebar detail
  document.querySelectorAll<HTMLElement>('[id^="gallery-image-card-"]').forEach((card) => {
    const id = card.id.split('gallery-image-card-')[1];
    if (!id || !imageIds.includes(id)) return;
    card.addEventListener('click', () => {
      selectedGalleryImage = images.find((img) => img.image_id === id) ?? null;

      // Highlight selected
      document
        .querySelectorAll<HTMLElement>('[id^="gallery-image-card-"]')
        .forEach((c) => c.classList.remove('ring-2'));
      card.classList.add('ring-2');

      // Update sidebar
      const sidebarImg = document.querySelector<HTMLImageElement>('#gallery-selected-image');
      if (sidebarImg) {
        sidebarImg.src = card.getAttribute('src') ?? '';
        sidebarImg.style.aspectRatio = String(
          Math.min(1, (selectedGalleryImage?.width ?? 1) / (selectedGalleryImage?.height ?? 1)),
        );
      }

      const tsEl = document.querySelector<HTMLElement>('#gallery-selected-image-timestamp');
      if (tsEl && selectedGalleryImage?.created_at) {
        tsEl.textContent = formatDate(new Date(selectedGalleryImage.created_at as string));
      }

      const titleEl = document.querySelector<HTMLElement>('#gallery-selected-image-title');
      const titleWrapper = document.querySelector<HTMLElement>('#gallery-selected-image-title-wrapper');
      if (titleEl) titleEl.textContent = selectedGalleryImage?.title ?? '';
      if (titleWrapper) {
        selectedGalleryImage?.title ? titleWrapper.classList.remove('hidden') : titleWrapper.classList.add('hidden');
      }

      const promptEl = document.querySelector<HTMLElement>('#gallery-selected-image-prompt');
      if (promptEl) {
        promptEl.innerHTML =
          imageGalleryCurrentTab === 'chart'
            ? codeWrapper(selectedGalleryImage?.prompt ?? '')
            : (selectedGalleryImage?.prompt ?? '');
      }

      const genIdEl = document.querySelector<HTMLElement>('#gallery-selected-image-gen-id');
      if (genIdEl) genIdEl.textContent = selectedGalleryImage?.gen_id ?? '';

      const previewBtn = document.querySelector<HTMLElement>('#gallery-preview-conversation-button');
      if (previewBtn) {
        previewBtn.dataset.conversationId = selectedGalleryImage?.conversation_id ?? '';
      }
    });
  });
}

