/**
 * Wire up tab buttons, search, selection bar, and sidebar interactions.
 *
 * Original: content.isolated.end.js lines 9482-9568
 */
export function addImageGalleryEventListeners(): void {
  const searchInput = document.querySelector<HTMLInputElement>('#gallery-search');
  let debounceTimer: ReturnType<typeof setTimeout> | undefined;
  searchInput?.addEventListener('input', () => {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
      resetSidebar();
      loadImageList();
    }, 300);
  });

  const tabs: [string, GalleryCategory][] = [
    ['#gallery-tab-dalle', 'dalle'],
    ['#gallery-tab-chart', 'chart'],
    ['#gallery-tab-upload', 'upload'],
    ['#gallery-tab-public', 'public'],
  ];

  tabs.forEach(([selector, category]) => {
    document.querySelector(selector)?.addEventListener('click', () => {
      if (imageGalleryCurrentTab === category) return;
      showAll = false;
      imageGalleryCurrentTab = category;

      // Update tab radio states
      tabs.forEach(([sel, cat]) => {
        const btn = document.querySelector<HTMLElement>(sel);
        if (btn) btn.dataset.state = cat === category ? 'checked' : 'unchecked';
      });

      if (searchInput) searchInput.value = '';
      resetSidebar();
      resetGallerySelection();
      loadImageList();
    });
  });

  // Selection bar buttons
  document.querySelector('#gallery-selection-cancel-button')?.addEventListener('click', () => {
    resetGallerySelection();
  });

  const downloadBtn = document.querySelector<HTMLElement>('#gallery-selection-download-button');
  downloadBtn?.addEventListener('click', async (e) => {
    await downloadSelectedImages(downloadBtn, selectedImageGalleryImageIds, null, !(e as MouseEvent).shiftKey);
  });

  // Sidebar prompt copy
  const copyBtn = document.querySelector<HTMLElement>('#gallery-selected-image-prompt-copy-button');
  copyBtn?.addEventListener('click', () => {
    const promptEl = document.querySelector<HTMLElement>('#gallery-selected-image-prompt');
    if (promptEl) {
      navigator.clipboard.writeText(promptEl.textContent ?? '');
      toast('Copied prompt to clipboard');
    }
  });

  // Gen ID copy
  const genIdBtn = document.querySelector<HTMLElement>('#gallery-selected-image-gen-id-copy-button');
  genIdBtn?.addEventListener('click', () => {
    if (genIdBtn) {
      navigator.clipboard.writeText(genIdBtn.innerText);
      toast('Copied Gen ID to clipboard');
    }
  });

  // Preview conversation — navigate to the conversation that produced this image
  const previewBtn = document.querySelector<HTMLElement>('#gallery-preview-conversation-button');
  previewBtn?.addEventListener('click', () => {
    const convId = previewBtn.dataset.conversationId;
    if (!convId) return;
    // Close gallery overlay, then navigate to the conversation
    document.querySelector('#image-gallery')?.remove();
    window.history.pushState({}, '', `/c/${convId}`);
    window.dispatchEvent(new PopStateEvent('popstate', { state: {} }));
  });
}

// ---------------------------------------------------------------------------
// Sidebar reset
// ---------------------------------------------------------------------------

function resetSidebar(): void {
  const img = document.querySelector<HTMLImageElement>('#gallery-selected-image');
  if (img) {
    img.src = chrome.runtime.getURL('images/loading.gif');
    img.style.aspectRatio = '1';
  }
  const ts = document.querySelector<HTMLElement>('#gallery-selected-image-timestamp');
  if (ts) ts.textContent = '...';
  const prompt = document.querySelector<HTMLElement>('#gallery-selected-image-prompt');
  if (prompt) prompt.innerHTML = '...';
  const genId = document.querySelector<HTMLElement>('#gallery-selected-image-gen-id');
  if (genId) genId.textContent = '';
}

