/**
 * Wire up the gallery hamburger menu button and its dropdown options.
 *
 * Original: content.isolated.end.js line 9141
 */
export function addImageGalleryMenuEventListener(): void {
  chrome.runtime.sendMessage({ type: 'checkHasSubscription' }, (hasSub) => {
    const menuBtn = document.querySelector<HTMLButtonElement>('#image-gallery-menu-button');
    if (!menuBtn) return;

    menuBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      e.preventDefault();
      closeMenus();
      const existing = document.querySelector('#image-gallery-menu-options');
      if (existing) {
        existing.remove();
        return;
      }
      menuBtn.insertAdjacentHTML('afterend', imageGalleryMenuOptions());
    });

    // Close on outside click
    document.body.addEventListener('click', (ev) => {
      const opts = document.querySelector('#image-gallery-menu-options');
      if (
        opts &&
        !(opts as HTMLElement).contains(ev.target as Node) &&
        !(menuBtn as HTMLElement).contains(ev.target as Node)
      ) {
        opts.remove();
      }
    });

    // Option click handlers
    document.body.addEventListener('click', async (ev) => {
      const target = (ev.target as HTMLElement).closest('[id^="image-gallery-menu-option-"]');
      if (!target) return;

      document.querySelector('#image-gallery-menu-options')?.remove();
      const action = target.id.split('image-gallery-menu-option-')[1];

      if (!hasSub) {
        openUpgradeModal();
        return;
      }

      if (action === 'download') {
        await downloadSelectedImages(menuBtn, selectedImageGalleryImageIds, null, !ev.shiftKey);
      }

      if (action === 'date-range-download') {
        showDateSelectorDialog(
          'Download Images',
          'Select date range',
          'Cancel',
          'Download',
          null,
          async (startDate, endDate) => {
            chrome.runtime.sendMessage(
              {
                type: 'getGalleryImagesByDateRange',
                detail: { category: imageGalleryCurrentTab, startDate, endDate },
              },
              async (images) => {
                await zipImages(images, menuBtn, menuBtn.cloneNode(true) as HTMLElement, !ev.shiftKey);
              },
            );
          },
          'green',
          true,
        );
      }

      if (action === 'public') {
        makeGalleryImagesPublic();
      }

      if (action === 'delete') {
        deleteGalleryImages();
      }
    });
  });
}

