/**
 * Fetch download URLs for images that are missing their image blob,
 * update the card src in the DOM, and upload them to the backend.
 */
export function loadMissingImages(images: GalleryImageNode[]): void {
  images?.forEach(async (img) => {
    if (img.image) return;

    // If we already have a local download URL, use it directly
    if (img.download_url && img.download_url.includes('localhost')) {
      const card =
        document.querySelector(`#gallery-image-card-${img.image_id}`) ||
        document.querySelector(`#image-picker-image-card-${img.image_id}`);
      if (card) (card as HTMLImageElement).src = img.download_url;
      return;
    }

    chrome.runtime.sendMessage(
      {
        type: 'getDownloadUrlFromFileId',
        detail: { conversationId: img.conversation_id, fileId: img.image_id },
      },
      (resp: any) => {
        if (!resp?.download_url) return;
        const card =
          document.querySelector(`#gallery-image-card-${img.image_id}`) ||
          document.querySelector(`#image-picker-image-card-${img.image_id}`);
        if (card) (card as HTMLImageElement).src = resp.download_url;

        // Upload to backend for persistent storage
        chrome.runtime.sendMessage({
          type: 'downloadAndUploadImages',
          detail: {
            images: [{ fileId: img.image_id, fileName: resp.file_name, downloadUrl: resp.download_url }],
          },
        });
      },
    );
  });
}

