/**
 * Fetch a page of gallery images and render into the image picker.
 *
 * Original: content.isolated.end.js line 9766
 */
async function getImagesForPage(page: number): Promise<void> {
  const list = document.querySelector('#image-picker-image-list');
  if (!list) return;

  const result = await chrome.runtime.sendMessage({
    type: 'getGalleryImages',
    detail: { pageNumber: page, category: 'all', searchTerm: '' },
  });
  if (!result?.results?.length) return;

  const hasNext = result.next;
  const cardsHtml = result.results
    .map(
      (img: GalleryImageNode) =>
        `<div class="group relative flex flex-col justify-start items-start gap-2 p-2 cursor-pointer" draggable="false"><img id="image-picker-image-card-${img.image_id}" src="${img.image || img.download_url}" alt="${(img.prompt ?? 'Generated by ChatGPT').replace(/[^a-zA-Z0-9 ]/gi, '')}" style="aspect-ratio:1;" class="bg-token-main-surface-primary border border-token-border-medium w-full row-span-4 mx-auto h-full rounded-md object-scale-down"><input type="checkbox" id="image-picker-checkbox-${img.image_id}" class="${selectedImagePickerImageIds.length === 0 ? 'invisible' : ''} absolute end-3 top-3 group-hover:visible" style="z-index: 11; cursor: pointer; border-radius: 2px;"></div>`,
    )
    .join('');

  if (page === 1) {
    list.innerHTML = cardsHtml;
  } else {
    document.querySelector('#load-more-images-button')?.parentElement?.remove();
    list.insertAdjacentHTML('beforeend', cardsHtml);
  }

  if (hasNext) {
    list.insertAdjacentHTML(
      'beforeend',
      '<div class="flex flex-col w-full justify-start items-start gap-2 p-2 w-full" style="aspect-ratio:1;"><div id="load-more-images-button" class="relative flex flex-col w-full h-full justify-center items-center text-token-text-primary text-2xl font-bold cursor-pointer bg-token-main-surface-secondary hover:shadow-xl rounded-xl">Load more...</div></div>',
    );
  }

  loadMissingImages(result.results);
  addImagePickerEventListeners(result.results, page);
}

/**
 * Attach event listeners to image picker cards, checkboxes, and load-more.
 *
 * Original: content.isolated.end.js line 9784
 */
function addImagePickerEventListeners(images: GalleryImageNode[], page: number): void {
  const imageIds = images.map((img) => img.image_id);

  // Click on image card → toggle checkbox
  document.querySelectorAll<HTMLElement>('[id^="image-picker-image-card"]').forEach((card) => {
    const id = card.id.split('image-picker-image-card-')[1];
    if (id && imageIds.includes(id)) {
      card.addEventListener('click', () => {
        const cb = document.querySelector(`#image-picker-checkbox-${id}`) as HTMLInputElement | null;
        cb?.click();
      });
    }
  });

  // Checkbox change → track selection
  document.querySelectorAll<HTMLInputElement>('[id^="image-picker-checkbox"]').forEach((cb) => {
    cb.addEventListener('click', (ev) => {
      ev.stopPropagation();
      if (selectedImagePickerImageIds.length >= 10 && cb.checked) {
        ev.preventDefault();
        toast('Maximum 10 images can be selected', 'error');
        return;
      }

      const id = cb.id.split('image-picker-checkbox-')[1]!;
      if (!imageIds.includes(id)) return;

      if (cb.checked && !selectedImagePickerImageIds.includes(id)) {
        const confirmBtn = document.querySelector('#image-picker-dialog #confirm-button') as HTMLButtonElement;
        if (confirmBtn) confirmBtn.disabled = false;
        if (selectedImagePickerImageIds.length === 0) {
          document.querySelectorAll('[id^="image-picker-checkbox"]').forEach((c) => c.classList.remove('invisible'));
        }
        const imgCard = document.querySelector(`#image-picker-image-card-${id}`) as HTMLElement | null;
        imgCard?.classList.add('opacity-50');
        selectedImagePickerImageIds.push(id);
        const count = document.querySelector('#image-picker-selection-count');
        if (count) count.textContent = `${selectedImagePickerImageIds.length} selected`;
      } else {
        selectedImagePickerImageIds = selectedImagePickerImageIds.filter((s) => s !== id);
        const count = document.querySelector('#image-picker-selection-count');
        if (count) count.textContent = `${selectedImagePickerImageIds.length} selected`;
        const imgCard = document.querySelector(`#image-picker-image-card-${id}`) as HTMLElement | null;
        imgCard?.classList.remove('opacity-50');
        if (selectedImagePickerImageIds.length === 0) resetImagePickerSelection();
      }
    });
  });

  // Load more button
  const loadMoreBtn = document.querySelector('#load-more-images-button') as HTMLElement | null;
  loadMoreBtn?.addEventListener('click', () => {
    loadMoreBtn.innerHTML = `<img style="object-fit:none;aspect-ratio:1;background-color: #111;" src="${chrome.runtime.getURL('images/loading.gif')}" class="row-span-4 mx-auto h-full rounded-md object-scale-down">`;
    getImagesForPage(page + 1);
  });

  // IntersectionObserver for auto-load
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          loadMoreBtn?.click();
          observer.disconnect();
        }
      });
    },
    { threshold: 0.5 },
  );
  if (loadMoreBtn) observer.observe(loadMoreBtn);
}

/**
 * Reset image picker selection state (uncheck all, disable confirm).
 *
 * Original: content.isolated.end.js line 9834
 */
function resetImagePickerSelection(): void {
  const confirmBtn = document.querySelector('#image-picker-dialog #confirm-button') as HTMLButtonElement | null;
  if (confirmBtn) confirmBtn.disabled = true;
  document.querySelectorAll<HTMLElement>('[id^="image-picker-image-card-"]').forEach((el) => {
    el.classList.remove('opacity-50');
  });
  document.querySelectorAll<HTMLInputElement>('[id^="image-picker-checkbox"]').forEach((cb) => {
    cb.checked = false;
    cb.classList.add('invisible');
  });
  const count = document.querySelector('#image-picker-selection-count');
  if (count) count.textContent = '0 selected';
}

